     1→import { access, lstat, mkdir, symlink, cp, unlink, rm } from "node:fs/promises";
     2→import type { Stats } from "node:fs";
     3→import path from "node:path";
     4→import { AGENT_REGISTRY } from "../config/agents.ts";
     5→import { resolveAgentSkillPath, getDeployMethod } from "./resolve.ts";
     6→import { UserError } from "../errors.ts";
     7→import type { AgentId, DeployAction, Manifest } from "../types.ts";
     8→
     9→export function planDeploy(
    10→  manifest: Manifest,
    11→  sourceDir: string,
    12→  detectedAgents: AgentId[],
    13→  home: string
    14→): DeployAction[] {
    15→  const method = getDeployMethod();
    16→  const actions: DeployAction[] = [];
    17→  const resolvedSourceDir = path.resolve(sourceDir);
    18→
    19→  for (const skill of manifest.skills) {
    20→    const source = path.resolve(sourceDir, skill.path);
    21→
    22→    if (source !== resolvedSourceDir && !source.startsWith(resolvedSourceDir + path.sep)) {
    23→      throw new UserError(
    24→        `Skill path "${skill.path}" resolves outside the repository root: ${source}`
    25→      );
    26→    }
    27→
    28→    for (const agentId of skill.agents) {
    29→      if (!detectedAgents.includes(agentId)) continue;
    30→
    31→      const agent = AGENT_REGISTRY.find((a) => a.id === agentId);
    32→      if (!agent) continue;
    33→
    34→      const target = resolveAgentSkillPath(agent, skill.name, home);
    35→
    36→      actions.push({ skill: skill.name, agent: agentId, source, target, method });
    37→    }
    38→  }
    39→
    40→  return actions;
    41→}
    42→
    43→export async function executeDeploy(
    44→  actions: DeployAction[],
    45→  dryRun: boolean,
    46→  verbose: boolean
    47→): Promise<{ succeeded: number; failed: Array<{ action: DeployAction; error: string }> }> {
    48→  let succeeded = 0;
    49→  const failed: Array<{ action: DeployAction; error: string }> = [];
    50→
    51→  for (const action of actions) {
    52→    const label = `${action.skill} -> ${action.agent}`;
    53→
    54→    try {
    55→      await access(action.source);
    56→    } catch {
    57→      const msg = `Source not found: ${action.source}`;
    58→      failed.push({ action, error: msg });
    59→      console.error(`  \x1b[31m✗\x1b[0m ${label}: ${msg}`);
    60→      continue;
    61→    }
    62→
    63→    if (dryRun) {
    64→      console.log(`  \x1b[36m○\x1b[0m ${label}`);
    65→      if (verbose) {
    66→        console.log(`    ${action.method}: ${action.source} -> ${action.target}`);
    67→      }
    68→      succeeded++;
    69→      continue;
    70→    }
    71→
    72→    try {
    73→      await removeExisting(action.target, verbose);
    74→      await mkdir(path.dirname(action.target), { recursive: true });
    75→
    76→      if (action.method === "symlink") {
    77→        await symlink(action.source, action.target, "dir");
    78→      } else {
    79→        await cp(action.source, action.target, { recursive: true });
    80→      }
    81→
    82→      console.log(`  \x1b[32m✓\x1b[0m ${label}`);
    83→      if (verbose) {
    84→        console.log(`    ${action.method}: ${action.source} -> ${action.target}`);
    85→      }
    86→      succeeded++;
    87→    } catch (err) {
    88→      const msg = err instanceof Error ? err.message : String(err);
    89→      failed.push({ action, error: msg });
    90→      console.error(`  \x1b[31m✗\x1b[0m ${label}: ${msg}`);
    91→    }
    92→  }
    93→
    94→  return { succeeded, failed };
    95→}
