     1→import { describe, it } from "node:test";
     2→import assert from "node:assert/strict";
     3→import { writeFileSync, mkdirSync, rmSync } from "node:fs";
     4→import path from "node:path";
     5→import os from "node:os";
     6→import { loadManifest } from "../src/config/manifest.ts";
     7→
     8→function makeTmpDir(): string {
     9→  const dir = path.join(os.tmpdir(), `ie-test-manifest-${Date.now()}-${Math.random().toString(36).slice(2)}`);
    10→  mkdirSync(dir, { recursive: true });
    11→  return dir;
    12→}
    13→
    14→describe("loadManifest", () => {
    15→  it("parses a valid manifest", async () => {
    16→    const dir = makeTmpDir();
    17→    try {
    18→      writeFileSync(
    19→        path.join(dir, "inception.json"),
    20→        JSON.stringify({
    21→          skills: [
    22→            { name: "test-skill", path: "skills/test-skill", agents: ["claude-code"] },
    23→          ],
    24→        })
    25→      );
    26→
    27→      const manifest = await loadManifest(dir);
    28→      assert.equal(manifest.skills.length, 1);
    29→      assert.equal(manifest.skills[0]!.name, "test-skill");
    30→      assert.deepEqual(manifest.skills[0]!.agents, ["claude-code"]);
    31→      assert.deepEqual(manifest.mcpServers, []);
    32→      assert.deepEqual(manifest.agentRules, []);
    33→    } finally {
    34→      rmSync(dir, { recursive: true });
    35→    }
    36→  });
    37→
    38→  it("throws on missing file", async () => {
    39→    await assert.rejects(loadManifest("/nonexistent/path"), /No inception\.json found/);
    40→  });
    41→
    42→  it("throws on invalid JSON", async () => {
    43→    const dir = makeTmpDir();
    44→    try {
    45→      writeFileSync(path.join(dir, "inception.json"), "not json{");
    46→      await assert.rejects(loadManifest(dir), /Invalid JSON/);
    47→    } finally {
    48→      rmSync(dir, { recursive: true });
    49→    }
    50→  });
    51→
    52→  it("throws on missing skills array", async () => {
    53→    const dir = makeTmpDir();
    54→    try {
    55→      writeFileSync(path.join(dir, "inception.json"), JSON.stringify({}));
    56→      await assert.rejects(loadManifest(dir), /"skills" must be an array/);
    57→    } finally {
    58→      rmSync(dir, { recursive: true });
    59→    }
    60→  });
    61→
    62→  it("throws on unknown agent ID", async () => {
    63→    const dir = makeTmpDir();
    64→    try {
    65→      writeFileSync(
