    28→export async function executeRevert(
    29→  actions: RevertAction[],
    30→  dryRun: boolean,
    31→  verbose: boolean
    32→): Promise<{ succeeded: number; skipped: number }> {
    33→  let succeeded = 0;
    34→  let skipped = 0;
    35→
    36→  for (const action of actions) {
    37→    const label = `${action.skill} -> ${action.agent}`;
    38→
    39→    let stat: Awaited<ReturnType<typeof lstat>>;
    40→    try {
    41→      stat = await lstat(action.target);
    42→    } catch {
    43→      console.log(`  \x1b[33m-\x1b[0m ${label} (not found, skipping)`);
    44→      skipped++;
    45→      continue;
    46→    }
    47→
    48→    if (dryRun) {
    49→      console.log(`  \x1b[36m○\x1b[0m ${label}`);
    50→      if (verbose) {
    51→        console.log(`    would remove: ${action.target}`);
    52→      }
    53→      succeeded++;
    54→      continue;
    55→    }
    56→
    57→    try {
    58→      if (stat.isSymbolicLink()) {
    59→        await unlink(action.target);
    60→      } else {
    61→        await rm(action.target, { recursive: true });
    62→      }
    63→      console.log(`  \x1b[32m✓\x1b[0m ${label}`);
    64→      if (verbose) {
    65→        console.log(`    removed: ${action.target}`);
    66→      }
    67→      succeeded++;
    68→    } catch (err) {
    69→      const msg = err instanceof Error ? err.message : String(err);
    70→      console.error(`  \x1b[31m✗\x1b[0m ${label}: ${msg}`);
    71→    }
    72→  }
    73→
    74→  return { succeeded, skipped };
    75→}
